/**
 * nodes-data.js — Single source of truth for all Fusion node definitions.
 *
 * PORT_COLOUR_HEX  — maps Markdown colour names to display hex values.
 * NODE_DETAIL      — rich per-node schema from Chapter databases.
 * FUSION_NODES_ALL — flat list used for the grid (name + category only).
 *
 * ── DATA SAFETY RULE ────────────────────────────────────────────────────────
 * ALL graph_payload values MUST use template literals (backticks), never
 * single- or double-quoted strings.  Fusion .setting code contains embedded
 * double-quoted strings, backslashes, and multi-line blocks that will silently
 * corrupt or throw a SyntaxError if wrapped in regular quotes.
 *
 *   CORRECT:   graph_payload: `{ Tools = ordered() { ... } }`,
 *   WRONG:     graph_payload: '{ Tools = ordered() { ... } }',
 *   WRONG:     graph_payload: "{ Tools = ordered() { ... } }",
 *
 * This applies to every entry in both NODE_DETAIL and EFFECTS_DETAIL.
 * ────────────────────────────────────────────────────────────────────────────
 */

// ─── Port colour map ─────────────────────────────────────────────────────────
